@* Displays a single task with title, assignee, priority badge, due date, and move buttons *@

<div class="card mb-2">
    <div class="card-body p-2">
        <h6 class="card-title mb-1">@Task.Title</h6>
        <p class="card-text mb-1 text-muted small">@Task.Assignee</p>
        <span class="badge @PriorityClass me-1">@Task.Priority</span>
        <small class="text-muted">@Task.DueDate.ToString("MMM dd")</small>
        <div class="mt-2 d-flex gap-1">
            @if (ShowMoveLeft)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="OnMoveLeft">← Move Left</button>
            }
            @if (ShowMoveRight)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="OnMoveRight">Move Right →</button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback OnMoveLeft { get; set; }
    [Parameter] public EventCallback OnMoveRight { get; set; }

    private string PriorityClass => Task.Priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };
}

@* Inline form for creating a new task within a column *@

<div class="card mb-2 border-primary">
    <div class="card-body p-2">
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Title" @bind="title" />
        </div>
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Assignee" @bind="assignee" />
        </div>
        <div class="mb-2">
            <select class="form-select form-select-sm" @bind="priority">
                <option value="High">High</option>
                <option value="Medium">Medium</option>
                <option value="Low">Low</option>
            </select>
        </div>
        <div class="mb-2">
            <input type="date" class="form-control form-control-sm" @bind="dueDate" />
        </div>
        <div class="d-flex gap-1">
            <button class="btn btn-primary btn-sm" @onclick="HandleSave" disabled="@isSaving">
                @(isSaving ? "Saving..." : "Save")
            </button>
            <button class="btn btn-outline-secondary btn-sm" @onclick="OnCancel" disabled="@isSaving">Cancel</button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string DefaultStatus { get; set; } = default!;
    [Parameter] public EventCallback<TaskItem> OnSave { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private string title = "";
    private string assignee = "";
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);
    private bool isSaving;

    private async Task HandleSave()
    {
        if (string.IsNullOrWhiteSpace(title)) return;

        isSaving = true;
        try
        {
            await OnSave.InvokeAsync(new TaskItem(0, title, assignee, priority, dueDate, DefaultStatus));
        }
        finally
        {
            isSaving = false;
        }
    }
}

@* Stats bar showing total tasks, per-column counts, and overdue count *@

<div class="d-flex flex-wrap gap-3 mb-3 p-3 bg-light rounded">
    <div><strong>Total:</strong> @TotalCount</div>
    <div><strong>To Do:</strong> @TodoCount</div>
    <div><strong>In Progress:</strong> @InProgressCount</div>
    <div><strong>Done:</strong> @DoneCount</div>
    <div class="@(OverdueCount > 0 ? "text-danger" : "")">
        <strong>Overdue:</strong> @OverdueCount
    </div>
</div>

@code {
    [Parameter] public int TotalCount { get; set; }
    [Parameter] public int TodoCount { get; set; }
    [Parameter] public int InProgressCount { get; set; }
    [Parameter] public int DoneCount { get; set; }
    [Parameter] public int OverdueCount { get; set; }
}

@* Search bar for filtering tasks by title *@

<div class="mb-3">
    <input type="text"
           class="form-control"
           placeholder="Search tasks by title..."
           value="@SearchText"
           @oninput="HandleInput" />
</div>

@code {
    [Parameter] public string SearchText { get; set; } = "";
    [Parameter] public EventCallback<string> OnSearchChanged { get; set; }

    private async Task HandleInput(ChangeEventArgs e)
    {
        await OnSearchChanged.InvokeAsync(e.Value?.ToString() ?? "");
    }
}

@* A single Kanban column displaying its tasks and an inline add-task form *@

<div class="col">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h5 class="mb-0">@ColumnName</h5>
            <span class="badge bg-secondary">@Tasks.Count</span>
        </div>
        <div class="card-body" style="min-height: 200px;">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          ShowMoveLeft="CanMoveLeft"
                          ShowMoveRight="CanMoveRight"
                          OnMoveLeft="() => OnMoveTask.InvokeAsync((task.Id, MoveLeftStatus!))"
                          OnMoveRight="() => OnMoveTask.InvokeAsync((task.Id, MoveRightStatus!))" />
            }

            @if (showForm)
            {
                <AddTaskForm DefaultStatus="@ColumnName"
                             OnSave="HandleTaskCreated"
                             OnCancel="() => showForm = false" />
            }
        </div>
        <div class="card-footer">
            <button class="btn btn-outline-primary btn-sm w-100" @onclick="() => showForm = true" disabled="@showForm">
                + Add Task
            </button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = default!;
    [Parameter] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public string? MoveLeftStatus { get; set; }
    [Parameter] public string? MoveRightStatus { get; set; }
    [Parameter] public EventCallback<(int TaskId, string NewStatus)> OnMoveTask { get; set; }
    [Parameter] public EventCallback<TaskItem> OnTaskCreated { get; set; }

    private bool showForm;

    private async Task HandleTaskCreated(TaskItem task)
    {
        await OnTaskCreated.InvokeAsync(task);
        showForm = false;
    }
}

@page "/board"
@using sv_602e0c49400b4a1384e176bfff80012a.Components.Board
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (isLoading)
{
    <div class="d-flex justify-content-center p-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-sm btn-outline-danger ms-2" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardSummaryBar TotalCount="tasks.Count"
                     TodoCount="todoTasks.Count"
                     InProgressCount="inProgressTasks.Count"
                     DoneCount="doneTasks.Count"
                     OverdueCount="overdueTasks.Count" />

    <BoardSearchBar SearchText="@searchText" OnSearchChanged="HandleSearchChanged" />

    <div class="row g-3">
        <BoardColumn ColumnName="To Do"
                     Tasks="filteredTodo"
                     CanMoveLeft="false"
                     CanMoveRight="true"
                     MoveRightStatus="In Progress"
                     OnMoveTask="HandleMoveTask"
                     OnTaskCreated="HandleTaskCreated" />

        <BoardColumn ColumnName="In Progress"
                     Tasks="filteredInProgress"
                     CanMoveLeft="true"
                     CanMoveRight="true"
                     MoveLeftStatus="To Do"
                     MoveRightStatus="Done"
                     OnMoveTask="HandleMoveTask"
                     OnTaskCreated="HandleTaskCreated" />

        <BoardColumn ColumnName="Done"
                     Tasks="filteredDone"
                     CanMoveLeft="true"
                     CanMoveRight="false"
                     MoveLeftStatus="In Progress"
                     OnMoveTask="HandleMoveTask"
                     OnTaskCreated="HandleTaskCreated" />
    </div>
}

@code {
    private List<TaskItem> tasks = new();
    private string searchText = "";
    private bool isLoading = true;
    private string? errorMessage;

    // Unfiltered column lists (used for summary counts)
    private List<TaskItem> todoTasks => tasks.Where(t => t.Status == "To Do").ToList();
    private List<TaskItem> inProgressTasks => tasks.Where(t => t.Status == "In Progress").ToList();
    private List<TaskItem> doneTasks => tasks.Where(t => t.Status == "Done").ToList();
    private List<TaskItem> overdueTasks => tasks.Where(t => t.DueDate.Date < DateTime.Today).ToList();

    // Filtered column lists (search applied)
    private List<TaskItem> filteredTodo => Filter(todoTasks);
    private List<TaskItem> filteredInProgress => Filter(inProgressTasks);
    private List<TaskItem> filteredDone => Filter(doneTasks);

    private List<TaskItem> Filter(List<TaskItem> items) =>
        string.IsNullOrWhiteSpace(searchText)
            ? items
            : items.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase)).ToList();

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        isLoading = true;
        errorMessage = null;

        try
        {
            tasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private void HandleSearchChanged(string value)
    {
        searchText = value;
    }

    private async Task HandleMoveTask((int TaskId, string NewStatus) move)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(move.TaskId, move.NewStatus);
            var index = tasks.FindIndex(t => t.Id == move.TaskId);
            if (index >= 0)
            {
                var old = tasks[index];
                tasks[index] = old with { Status = move.NewStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }

    private async Task HandleTaskCreated(TaskItem formData)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(formData.Title, formData.Assignee, formData.Priority, formData.DueDate);
            tasks.Add(created);
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }
}

